const parseBase64JSON = <T = unknown>(header: string): T | undefined => {
	if (typeof req.headers[header] === 'string') {
		try {
			return JSON.parse(Buffer.from(req.headers[header] as string, 'base64').toString('utf8'));
		} catch {}
	}
};

